from numpy.typing import NDArray
def decay_toward_stationary(pmfs: NDArray[np.float_],                      #Array of shape (N, K) or (K,), where each row sums to 1.
                             gammas: NDArray[np.float_]|float,                    #Array of shape (N,), or scalar in shape (1,) or (), each gamma ∈ [0, 1].
                             stationary_distribution: NDArray[np.float_]    #Row vector of shape (K,) (sums to 1) used as the target mix.

                             ) -> NDArray[np.float_]:
    """
    Decay each row-PMF toward a given stationary distribution.
    Returns:
        Array of shape (N, K), where each row is mixed with stationary_distribution.
        new_pmfs = (1 - gamma_i) * pmfs[i, :] + gamma_i * stationary_distribution
    """
    # Ensure 2D with rows as PMFs
    if pmfs.ndim == 1:
        pmfs = pmfs[np.newaxis, :]  # (1, K)
    elif pmfs.ndim != 2:
        raise ValueError("pmfs must be 1D or 2D (rows are PMFs).")

    # Basic validity: rows sum to 1
    if not np.allclose(pmfs.sum(axis=1), 1.0, atol=1e-9):
        raise ValueError("All rows in pmfs must sum to 1.")

    N, K = pmfs.shape

    # Validate and shape stationary distribution
    sd = np.asarray(stationary_distribution).squeeze()
    if sd.ndim != 1 or sd.shape[0] != K:
        raise ValueError(f"stationary_distribution must be shape ({K},), got {sd.shape}.")
    if np.any(sd < 0):
        raise ValueError("stationary_distribution must be nonnegative.")
    if not np.allclose(sd.sum(), 1.0, atol=1e-9):
        raise ValueError("stationary_distribution must sum to 1.")
    sd = np.broadcast_to(sd, (N, K))  # same stationary row for all rows

    # Validate and broadcast gammas
    if np.isscalar(gammas) or (isinstance(gammas, np.ndarray) and gammas.shape == (1,)):
        gammas = np.full((N,), gammas)
    else:
        gammas = np.asarray(gammas)
        if gammas.ndim == 2 and gammas.shape == (N, 1):
            gammas = gammas.ravel()
        if gammas.shape != (N,):
            raise ValueError(f"gammas must be scalar or shape ({N},), got {gammas.shape}.")

    if not np.all((0.0 <= gammas) & (gammas <= 1.0)):
        raise ValueError("All gammas must be in [0, 1].")

    gammas = gammas[:, np.newaxis]  # (N, 1) for broadcasting over columns

    # Mix toward stationary distribution
    new_pmfs = (1.0 - gammas) * pmfs + gammas * sd
    return new_pmfs

